import numpy as np

class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces in their starting positions
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = 1  # White pieces
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = -1  # Black pieces

    def print_board(self):
        # Print the board in a readable format
        for row in self.board:
            print(" ".join(str(piece) for piece in row))

    def move_piece(self, start, end):
        # Move a piece from start to end position
        self.board[end[0], end[1]] = self.board[start[0], start[1]]
        self.board[start[0], start[1]] = 0

    def is_valid_move(self, start, end):
        # Check if the move is valid
        piece = self.board[start[0], start[1]]
        direction = -1 if piece == 1 else 1
        if abs(end[0] - start[0]) == 2 and abs(end[1] - start[1]) == 2:
            mid = ((start[0] + end[0]) // 2, (start[1] + end[1]) // 2)
            return self.board[mid[0], mid[1]] != 0 and self.board[end[0], end[1]] == 0
        if abs(end[0] - start[0]) == 1 and abs(end[1] - start[1]) == 1:
            return self.board[end[0], end[1]] == 0
        return False

    def king_piece(self, pos):
        # King a piece if it reaches the other side of the board
        row, col = pos
        if row == 7 and self.board[row, col] == 1:
            self.board[row, col] = 2
        elif row == 0 and self.board[row, col] == -1:
            self.board[row, col] = -2

    def check_winner(self):
        # Check for a winner
        if np.sum(self.board) == 0:
            return "Black wins"
        elif np.sum(self.board) > 0:
            return "White wins"
        else:
            return None
